    /**
     * @ignore
     * @method
     * @name myriad#clobOrderMessage
     * @description normalises a fetched order-book order into a typed-data message (uint256 fields as strings, uint8 fields as ints)
     * @returns {object} the typed-data message
     */
    public Object clobOrderMessage(Object rawOrder)
    {
        return new java.util.HashMap<String, Object>() {{
            put( "trader", MyriadCore.this.safeString(rawOrder, "trader") );
            put( "marketId", MyriadCore.this.safeString(rawOrder, "marketId") );
            put( "outcomeId", MyriadCore.this.safeInteger(rawOrder, "outcomeId", 0) );
            put( "side", MyriadCore.this.safeInteger(rawOrder, "side", 0) );
            put( "amount", MyriadCore.this.safeString(rawOrder, "amount") );
            put( "price", MyriadCore.this.safeString(rawOrder, "price") );
            put( "minFillAmount", MyriadCore.this.safeString(rawOrder, "minFillAmount", "0") );
            put( "nonce", MyriadCore.this.safeString(rawOrder, "nonce") );
            put( "expiration", MyriadCore.this.safeString(rawOrder, "expiration", "0") );
        }};
    }

    /**
     * @ignore
     * @method
     * @name myriad#toOrderbookWei
     * @description scales a decimal value by 1e18 and truncates to an integer wei string
     * @returns {string} the integer wei string
     */
    public Object toOrderbookWei(Object value)
    {
        Object valueStr = this.numberToString(value);
        Object scaled = Precise.stringMul(valueStr, "1000000000000000000");
        // use > -1 (not >= 0): when '.' is absent PHP's mb_strpos returns false, and false >= 0
        // coerces to true (wrongly truncating to empty), whereas false > -1 correctly coerces to false
        Object dotIndex = Helpers.getIndexOf(scaled, ".");
        if (Helpers.isTrue(Helpers.isGreaterThan(dotIndex, Helpers.opNeg(1))))
        {
            return Helpers.slice(scaled, 0, dotIndex);
        }
        return scaled;
    }

    public Object parseOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "open", "open" );
            put( "pending", "open" );
            put( "partially_filled", "open" );
            put( "filled", "closed" );
            put( "cancelled", "canceled" );
            put( "canceled", "canceled" );
            put( "expired", "expired" );
        }};
        return this.safeString(statuses, status, status);
    }

    public Object parseOrder(Object order, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object inner = this.safeDict(order, "order", new java.util.HashMap<String, Object>() {{}});
        Object orderHash = this.safeString2(order, "orderHash", "hash");
        Object sideInt = this.safeInteger(inner, "side");
        Object side = ((Helpers.isTrue((Helpers.isEqual(sideInt, 1))))) ? "sell" : "buy";
        Object amountWei = this.safeString(inner, "amount");
        Object priceWei = this.safeString(inner, "price");
        Object filledWei = this.safeString(order, "filledAmount");
        Object amount = ((Helpers.isTrue((Helpers.isEqual(amountWei, null))))) ? null : this.parseNumber(Precise.stringDiv(amountWei, "1000000000000000000"));
        Object price = ((Helpers.isTrue((Helpers.isEqual(priceWei, null))))) ? null : this.parseNumber(Precise.stringDiv(priceWei, "1000000000000000000"));
        Object filled = ((Helpers.isTrue((Helpers.isEqual(filledWei, null))))) ? null : this.parseNumber(Precise.stringDiv(filledWei, "1000000000000000000"));
        Object statusRaw = this.safeStringLower(order, "status");
        Object status = this.parseOrderStatus(statusRaw);
        Object timestamp = this.parse8601(this.safeString(order, "createdAt"));
        Object tif = this.safeStringUpper(order, "timeInForce");
        Object isMarketTif = Helpers.isTrue((Helpers.isEqual(tif, "FOK"))) || Helpers.isTrue((Helpers.isEqual(tif, "FAK")));
        // resolve the outcome from market/outcome ids when no market was passed (e.g. fetchOrders without a outcome)
        Object outcome = ((Helpers.isTrue((Helpers.isEqual(market, null))))) ? null : this.safeString(market, "outcome");
        Object outcomeObj = market;
        if (Helpers.isTrue(Helpers.isEqual(outcome, null)))
        {
            // the REST order has no top-level networkId; order book lives on the default network
            Object networkId = this.safeString2(order, "networkId", "network_id", this.safeString(this.options, "defaultNetworkId", "56"));
            Object marketId = this.safeString(inner, "marketId");
            Object outcomeId = this.safeString(inner, "outcomeId");
            Object composite = null;
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(networkId, null))) && Helpers.isTrue((!Helpers.isEqual(marketId, null)))) && Helpers.isTrue((!Helpers.isEqual(outcomeId, null)))))
            {
                composite = Helpers.add(Helpers.add(Helpers.add(Helpers.add(networkId, ":"), marketId), "/"), outcomeId);
            }
            outcomeObj = this.safeOutcome(composite, ((Object)market));
            outcome = this.safeString(outcomeObj, "outcome");
        }
        final Object finalOutcome = outcome;
        final Object finalOutcomeObj = outcomeObj;
        final Object finalTif = tif;
        return this.safePredictionOrder(new java.util.HashMap<String, Object>() {{
            put( "id", orderHash );
            put( "clientOrderId", null );
            put( "info", order );
            put( "timestamp", timestamp );
            put( "datetime", MyriadCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "outcome", finalOutcome );
            put( "outcomeId", MyriadCore.this.safeString2(finalOutcomeObj, "outcomeId", "id") );
            put( "label", MyriadCore.this.safeString(finalOutcomeObj, "label") );
            put( "market", MyriadCore.this.safeString(finalOutcomeObj, "market") );
            put( "type", ((Helpers.isTrue(isMarketTif))) ? "market" : "limit" );
            put( "timeInForce", finalTif );
            put( "postOnly", (Helpers.isEqual(finalTif, "PO")) );
            put( "side", side );
            put( "price", price );
            put( "triggerPrice", null );
            put( "amount", amount );
            put( "filled", filled );
            put( "remaining", null );
            put( "cost", null );
            put( "average", null );
            put( "status", status );
            put( "fee", null );
            put( "trades", null );
        }}, market);
    }

    /**
     * @method
     * @name myriad#cancelOrder
     * @description cancels an open order book order by its hash (re-signs the original order to prove ownership; gasless)
     * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da8281b58c5adb2f5998eec8
     * @param {string} id the order hash returned by createOrder
     * @param {string} [outcome] unified outcome the order belongs to
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order structure](https://docs.ccxt.com/#/?id=order-structure)
     */
    public java.util.concurrent.CompletableFuture<Object> cancelOrder(Object id, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object outcome = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.privateKey, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " cancelOrder() requires a privateKey to sign the cancellation")) ;
            }
            Object fetched = (this.myriadPublicGetOrdersHash(this.extend(new java.util.HashMap<String, Object>() {{
                put( "hash", id );
            }}, parameters))).join();
            Object rawOrder = this.safeDict(fetched, "order", new java.util.HashMap<String, Object>() {{}});
            Object networkId = this.safeString2(fetched, "networkId", "network_id", this.safeString(this.options, "defaultNetworkId", "56"));
            Object message = this.clobOrderMessage(rawOrder);
            Object signature = this.signClobOrder(message, networkId);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "hash", id );
                put( "order", message );
                put( "signature", signature );
                put( "network_id", MyriadCore.this.parseToInt(networkId) );
            }};
            Object response = (this.myriadPublicDeleteOrdersHash(request)).join();
            Object status = this.safeString(response, "status", "canceled");
            Object wrapper = this.extend(fetched, new java.util.HashMap<String, Object>() {{
                put( "status", status );
                put( "networkId", networkId );
            }});
            Object market = null;
            if (Helpers.isTrue(!Helpers.isEqual(outcome, null)))
            {
                (this.loadOutcomes()).join();
                market = this.outcome(outcome);
            }
            return this.parseOrder(wrapper, ((Object)market));
        });

    }

    /**
     * @method
     * @name myriad#cancelAllOrders
     * @description cancels all open order book orders for the wallet, optionally scoped to one market (gasless)
     * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da8281e7a14cd34e6a716761
     * @param {string} [outcome] unified outcome; when omitted cancels across all markets
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} the raw response with the count of cancelled orders
     */
    public java.util.concurrent.CompletableFuture<Object> cancelAllOrders(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object outcome = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.privateKey, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " cancelAllOrders() requires a privateKey to sign the cancellation")) ;
            }
            Object trader = this.ethGetAddressFromPrivateKey(this.privateKey);
            Object marketId = this.safeString(parameters, "market_id", "0");
            Object networkId = this.safeString(parameters, "network_id", this.safeString(this.options, "defaultNetworkId", "56"));
            if (Helpers.isTrue(!Helpers.isEqual(outcome, null)))
            {
                (this.loadOutcomes()).join();
                Object outcomeObj = this.outcome(outcome);
                Object info = this.safeDict(outcomeObj, "info", new java.util.HashMap<String, Object>() {{}});
                marketId = this.safeString(info, "marketId", marketId);
                networkId = this.safeString(info, "networkId", networkId);
            }
            // timestamp defaults to now (unix seconds) but can be pinned via params for idempotent retries
            Object timestamp = this.safeString(parameters, "timestamp", this.numberToString(this.seconds()));
            final Object finalMarketId = marketId;
            Object message = new java.util.HashMap<String, Object>() {{
                put( "trader", trader );
                put( "marketId", finalMarketId );
                put( "timestamp", timestamp );
            }};
            Object signature = this.signCancelAll(message, networkId);
            final Object finalNetworkId = networkId;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "trader", trader );
                put( "market_id", MyriadCore.this.parseToInt(finalMarketId) );
                put( "timestamp", timestamp );
                put( "signature", signature );
                put( "network_id", MyriadCore.this.parseToInt(finalNetworkId) );
            }};
            return (this.myriadPublicPostOrdersCancelAll(request)).join();
        });

    }

    /**
     * @method
     * @name myriad#cancelOrders
     * @description cancels multiple open order book orders by hash in one request (gasless)
     * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da828177961fd94a6055966f
     * @param {string[]} ids the order hashes to cancel
     * @param {string} [outcome] not used by myriad cancelOrders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [order structures](https://docs.ccxt.com/#/?id=order-structure)
     */
    public java.util.concurrent.CompletableFuture<Object> cancelOrders(Object ids, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object outcome = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.privateKey, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " cancelOrders() requires a privateKey to sign the cancellations")) ;
            }
            Object idsLength = Helpers.getArrayLength(ids);
            Object signedOrders = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object wrappers = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object networkId = this.safeString(this.options, "defaultNetworkId", "56");
            for (var i = 0; Helpers.isLessThan(i, idsLength); i++)
            {
                Object id = Helpers.GetValue(ids, i);
                Object fetched = (this.myriadPublicGetOrdersHash(new java.util.HashMap<String, Object>() {{
                    put( "hash", id );
                }})).join();
                Object rawOrder = this.safeDict(fetched, "order", new java.util.HashMap<String, Object>() {{}});
                networkId = this.safeString2(fetched, "networkId", "network_id", networkId);
                Object message = this.clobOrderMessage(rawOrder);
                Object signature = this.signClobOrder(message, networkId);
                ((java.util.List<Object>)signedOrders).add(new java.util.HashMap<String, Object>() {{
                    put( "order", message );
                    put( "signature", signature );
                }});
    final Object finalNetworkId = networkId;
                            ((java.util.List<Object>)wrappers).add(this.extend(fetched, new java.util.HashMap<String, Object>() {{
                    put( "status", "canceled" );
                    put( "networkId", finalNetworkId );
                }}));
            }
            final Object finalNetworkId = networkId;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "orders", signedOrders );
                put( "network_id", MyriadCore.this.parseToInt(finalNetworkId) );
            }};
            (this.myriadPublicPostOrdersCancelBatch(this.extend(request, parameters))).join();
            return this.parsePredictionOrders(wrappers);
        });

    }

