    /**
     * @method
     * @name myriad#fetchTradingFee
     * @description fetches the buy/sell fee rates for a market outcome
     * @see https://docs.myriad.markets/builders/myriad-api-reference
     * @param {string} outcome unified outcome or outcome id
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [fee structure](https://docs.ccxt.com/#/?id=fee-structure)
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTradingFee(Object outcome, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadOutcomes()).join();
            Object outcomeObj = this.outcome(outcome);
            Object info = this.safeDict(outcomeObj, "info", new java.util.HashMap<String, Object>() {{}});
            Object request = new java.util.HashMap<String, Object>() {{
                put( "id", MyriadCore.this.safeString(info, "marketId") );
                put( "network_id", MyriadCore.this.safeString(info, "networkId") );
            }};
            Object response = (this.myriadPublicGetMarketsId(this.extend(request, parameters))).join();
            //
            //     {
            //         "fees": {
            //             "buy": { "fee": "0.02", "treasury_fee": "0.01", "distributor_fee": "0.01" },
            //             "sell": { "fee": "0", "treasury_fee": "0", "distributor_fee": "0" }
            //         }
            //     }
            //
            Object fees = this.safeDict(response, "fees", new java.util.HashMap<String, Object>() {{}});
            Object buy = this.safeDict(fees, "buy", new java.util.HashMap<String, Object>() {{}});
            Object sell = this.safeDict(fees, "sell", new java.util.HashMap<String, Object>() {{}});
            return new java.util.HashMap<String, Object>() {{
                put( "info", response );
                put( "outcome", MyriadCore.this.safeOutcomeSymbol(null, ((Object)outcomeObj)) );
                put( "outcomeId", MyriadCore.this.safeString(outcomeObj, "outcomeId") );
                put( "maker", MyriadCore.this.safeNumber(sell, "fee") );
                put( "taker", MyriadCore.this.safeNumber(buy, "fee") );
                put( "percentage", true );
                put( "tierBased", false );
            }};
        });

    }

    /**
     * @ignore
     * @method
     * @name myriad#parseTicker
     * @description parses a raw myriad market object into a unified ticker for the specified outcome
     * @param {object} raw the raw myriad market object
     * @param {object} [market] the outcome object the ticker belongs to
     * @returns {object} a [ticker structure](https://docs.ccxt.com/#/?id=ticker-structure)
     */
    public Object parseTicker(Object raw, Object... optionalArgs)
    {
        //
        //     {
        //         "id": "756",
        //         "networkId": "2741",
        //         "slug": "will-trump-capture-another-president-before-his-birthday",
        //         "title": "Will Trump capture another president before his birthday?",
        //         "description": "string"
        //         "publishedAt": "2026-01-16T18:05:36.000Z",
        //         "expiresAt": "2026-06-14T04:59:00.000Z",
        //         "resolvesAt": null,
        //         "fees": {
        //             "buy": { "fee": "0.01", "treasury_fee": "0.01", "distributor_fee": "0.01" },
        //             "sell": { "fee": "0", "treasury_fee": "0", "distributor_fee": "0" },
        //             "treasury": "0x5E3EbEc100e2294C0EB2264FC96225dF067AAaa3",
        //             "distributor": "0xE44984C586FeBB31605D23b6316cA11B6f4D86b2"
        //         },
        //         "state": "open",
        //         "voided": false,
        //         "resolvedOutcomeId": "-1",
        //         "topics": [ "Politics" ],
        //         "resolutionSource": "https://www.whitehouse.gov/",
        //         "resolutionTitle": "White House",
        //         "token": {
        //             "name": "Bridged USDC (Stargate)",
        //             "address": "0x84A71ccD554Cc1b02749b35d22F684CC8ec987e1",
        //             "symbol": "USDC.e",
        //             "decimals": "6"
        //         },
        //         "imageUrl": "https://cdn.polkamarkets.com/Qma9FAX15kHewT8vm61vykGA9bqQhNdDLvEbQWSp72i3PQ",
        //         "bannerImageUrl": "https://imagedelivery.net/YN1-rdnufJQJCgu3i1CbVw/255d431f-1bb4-4d90-032b-d1f7032e8000/public",
        //         "ogImageUrl": "https://imagedelivery.net/YN1-rdnufJQJCgu3i1CbVw/cf1af79c-07b9-40f0-283b-ed59865b3c00/public",
        //         "liquidity": "2000",
        //         "liquidityPrice": "0.32532445",
        //         "volume": "10891.236893",
        //         "volume24h": "0.939",
        //         "volumeNotional": "13570.426814",
        //         "volumeNotional24h": "1.028382",
        //         "users": "122",
        //         "shares": "4098.474144",
        //         "featured": false,
        //         "featuredAt": null,
        //         "inPlay": false,
        //         "inPlayStartsAt": null,
        //         "perpetual": false,
        //         "moneyline": false,
        //         "executionMode": "0",
        //         "tradingModel": "amm",
        //         "topHolders": [
        //             "0x8A611AEE71b6448a6F99B6001D1234d020f7d546",
        //             "0x2993249A3D107B759c886a4BD4e02B70d471eA9B",
        //             "0x82a5b3BD2A9216369537583f63fa576a1D57c7E7"
        //         ],
        //         "outcomes": [
        //             {
        //                 "id": "0",
        //                 "title": "Yes",
        //                 "shares": "3742.174971",
        //                 "sharesHeld": "138.741271",
        //                 "price": "0.08693459",
        //                 "closingPrice": null,
        //                 "priceChange24h": "0.00045828",
        //                 "imageUrl": "https://cdn.polkamarkets.com/Qma9FAX15kHewT8vm61vykGA9bqQhNdDLvEbQWSp72i3PQ",
        //                 "holders": "7",
        //                 "tokenId": "1512",
        //                 "price_charts": [Array]
        //             },
        //         ],
        //         "eventId": null,
        //         "outcomeIndex": null,
        //         "negRisk": false,
        //         "externalSources": []
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object outcomeId = ((Helpers.isTrue(market))) ? this.safeString(Helpers.GetValue(market, "info"), "outcomeId") : null;
        Object outcomes = (java.util.List<Object>)(this.safeList(raw, "outcomes", new java.util.ArrayList<Object>(java.util.Arrays.asList())));
        Object price = null;
        Object change = null;
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(outcomes)); i++)
        {
            Object o = Helpers.GetValue(outcomes, i);
            if (Helpers.isTrue(Helpers.isEqual(this.safeString(o, "outcomeId", this.safeString(o, "id")), outcomeId)))
            {
                price = this.safeNumber(o, "price");
                change = this.safeNumber(o, "priceChange24h");
                break;
            }
        }
        Object now = this.milliseconds();
        final Object finalPrice = price;
        final Object finalChange = change;
        return this.safePredictionTicker(new java.util.HashMap<String, Object>() {{
            put( "outcome", MyriadCore.this.safeString(market, "outcome") );
            put( "outcomeId", MyriadCore.this.safeString(market, "id") );
            put( "label", MyriadCore.this.safeString(market, "label") );
            put( "market", MyriadCore.this.safeString(market, "market") );
            put( "timestamp", now );
            put( "datetime", MyriadCore.this.iso8601(now) );
            put( "high", null );
            put( "low", null );
            put( "bid", finalPrice );
            put( "bidVolume", null );
            put( "ask", finalPrice );
            put( "askVolume", null );
            put( "vwap", null );
            put( "open", null );
            put( "close", finalPrice );
            put( "last", finalPrice );
            put( "previousClose", null );
            put( "change", finalChange );
            put( "percentage", finalChange );
            put( "average", finalPrice );
            put( "baseVolume", MyriadCore.this.safeNumber(raw, "volume24h") );
            put( "quoteVolume", MyriadCore.this.safeNumber(raw, "volumeNotional24h") );
            put( "info", raw );
        }}, market);
    }

    /**
     * @method
     * @name myriad#fetchOrderBook
     * @description fetches the real order book for order-book markets, or synthesizes a one-level book from the AMM price otherwise
     * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da8281bba6aaf24dd61f2bb1
     * @param {string} outcome unified outcome like TRUMP_WIN:YES or an outcome id
     * @param {int} [limit] not used by myriad fetchOrderBook
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order book structure](https://docs.ccxt.com/#/?id=order-book-structure)
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOrderBook(Object outcome, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object limit = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadOutcomes()).join();
            Object outcomeObj = this.outcome(outcome);
            Object networkId = this.safeString(Helpers.GetValue(outcomeObj, "info"), "networkId");
            Object marketId = this.safeString(Helpers.GetValue(outcomeObj, "info"), "marketId");
            Object outcomeId = this.safeString(Helpers.GetValue(outcomeObj, "info"), "outcomeId");
            Object tradingModel = this.safeString(Helpers.GetValue(outcomeObj, "info"), "tradingModel", "amm");
            if (Helpers.isTrue(Helpers.isEqual(tradingModel, "ob")))
            {
                Object obRequest = new java.util.HashMap<String, Object>() {{
                    put( "id", marketId );
                    put( "network_id", networkId );
                    put( "outcome", outcomeId );
                }};
                Object obResponse = (this.myriadPublicGetMarketsIdOrderbook(this.extend(obRequest, parameters))).join();
                //
                //     {
                //         "bids": [ [ "980000000000000000", "258412594752186597376" ] ],
                //         "asks": [ [ "990000000000000000", "151975683890577539072" ] ]
                //     }
                //
                return this.safePredictionOrderBook(this.parseWeiOrderBook(obResponse, this.safeOutcomeSymbol(outcome, outcomeObj)), outcomeObj);
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "id", marketId );
                put( "network_id", networkId );
            }};
            Object response = (this.myriadPublicGetMarketsId(this.extend(request, parameters))).join();
            //
            //     {
            //         "id": "756",
            //         "networkId": "2741",
            //         "slug": "will-trump-capture-another-president-before-his-birthday",
            //         "title": "Will Trump capture another president before his birthday?",
            //         "shortName": null,
            //         "description": "### **Market Dates:**"
            //         "publishedAt": "2026-01-16T18:05:36.000Z",
            //         "expiresAt": "2026-06-14T04:59:00.000Z",
            //         "resolvesAt": null,
            //         "fees": {
            //             "buy": { "fee": "0.01", "treasury_fee": "0.01", "distributor_fee": "0.01" },
            //             "sell": { "fee": "0", "treasury_fee": "0", "distributor_fee": "0" },
            //             "treasury": "0x5E3EbEc100e2294C0EB2264FC96225dF067AAaa3",
            //             "distributor": "0xE44984C586FeBB31605D23b6316cA11B6f4D86b2"
            //         },
            //         "state": "open",
            //         "voided": false,
            //         "resolvedOutcomeId": "-1",
            //         "topics": [ "Politics" ],
            //         "resolutionSource": "https://www.whitehouse.gov/",
            //         "resolutionTitle": "White House",
            //         "token": {
            //             "name": "Bridged USDC (Stargate)",
            //             "address": "0x84A71ccD554Cc1b02749b35d22F684CC8ec987e1",
            //             "symbol": "USDC.e",
            //             "decimals": "6"
            //         },
            //         "imageUrl": "https://cdn.polkamarkets.com/Qma9FAX15kHewT8vm61vykGA9bqQhNdDLvEbQWSp72i3PQ",
            //         "bannerImageUrl": "https://imagedelivery.net/YN1-rdnufJQJCgu3i1CbVw/255d431f-1bb4-4d90-032b-d1f7032e8000/public",
            //         "ogImageUrl": "https://imagedelivery.net/YN1-rdnufJQJCgu3i1CbVw/d3d60089-3d08-45ac-aa9d-139156e3f900/public",
            //         "liquidity": "2000",
            //         "liquidityPrice": "0.29322839",
            //         "volume": "11396.236893",
            //         "volume24h": "500",
            //         "volumeNotional": "14101.517862",
            //         "volumeNotional24h": "525.779869",
            //         "users": "124",
            //         "shares": "4547.083096",
            //         "featured": false,
            //         "featuredAt": null,
            //         "inPlay": false,
            //         "inPlayStartsAt": null,
            //         "perpetual": false,
            //         "moneyline": false,
            //         "executionMode": "0",
            //         "tradingModel": "amm",
            //         "topHolders": [
            //             "0x8A611AEE71b6448a6F99B6001D1234d020f7d546",
            //             "0x2993249A3D107B759c886a4BD4e02B70d471eA9B"
            //         ],
            //         "outcomes": [
            //             {
            //                 "id": "0",
            //                 "title": "Yes",
            //                 "shares": "4232.024971",
            //                 "sharesHeld": "138.741271",
            //                 "price": "0.06928796",
            //                 "closingPrice": null,
            //                 "priceChange24h": "-0.20109988",
            //                 "imageUrl": "https://cdn.polkamarkets.com/Qma9FAX15kHewT8vm61vykGA9bqQhNdDLvEbQWSp72i3PQ",
            //                 "holders": "7",
            //                 "tokenId": "1512",
            //                 "price_charts": [Array]
            //             }
            //         ],
            //         "eventId": null,
            //         "outcomeIndex": null,
            //         "negRisk": false,
            //         "externalSources": []
            //     }
            //
            Object outcomes = (java.util.List<Object>)(this.safeList(response, "outcomes", new java.util.ArrayList<Object>(java.util.Arrays.asList())));
            Object price = null;
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(outcomes)); i++)
            {
                Object o = Helpers.GetValue(outcomes, i);
                if (Helpers.isTrue(Helpers.isEqual(this.safeString(o, "outcomeId", this.safeString(o, "id")), outcomeId)))
                {
                    price = this.safeNumber(o, "price");
                    break;
                }
            }
            Object timestamp = this.milliseconds();
            // AMM: synthesize a single bid/ask pair around the current implied price, clamped into the valid (0, 1) range
            Object bid = null;
            Object ask = null;
            if (Helpers.isTrue(!Helpers.isEqual(price, null)))
            {
                if (Helpers.isTrue(Helpers.isGreaterThan(price, 0.001)))
                {
                    bid = this.parseNumber(Precise.stringSub(this.numberToString(price), "0.001"));
                }
                if (Helpers.isTrue(Helpers.isLessThan(price, 0.999)))
                {
                    ask = this.parseNumber(Precise.stringAdd(this.numberToString(price), "0.001"));
                }
            }
            // the synthetic size must be a parsed float, an int literal breaks the typed go wrapper conversion
            Object synthSize = this.parseNumber("9999");
            Object bids = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            if (Helpers.isTrue(!Helpers.isEqual(bid, null)))
            {
                ((java.util.List<Object>)bids).add(new java.util.ArrayList<Object>(java.util.Arrays.asList(bid, synthSize)));
            }
            Object asks = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            if (Helpers.isTrue(!Helpers.isEqual(ask, null)))
            {
                ((java.util.List<Object>)asks).add(new java.util.ArrayList<Object>(java.util.Arrays.asList(ask, synthSize)));
            }
            Object orderbook = new java.util.HashMap<String, Object>() {{
                put( "outcome", MyriadCore.this.safeOutcomeSymbol(outcome, outcomeObj) );
                put( "bids", bids );
                put( "asks", asks );
                put( "timestamp", timestamp );
                put( "datetime", MyriadCore.this.iso8601(timestamp) );
                put( "nonce", null );
            }};
            return this.safePredictionOrderBook(orderbook, outcomeObj);
        });

    }

    /**
     * @ignore
     * @method
     * @name myriad#parseWeiOrderBook
     * @description parses an order book whose price and amount levels are 1e18-scaled integer strings
     * @param {object} response the raw orderbook response with bids and asks arrays
     * @param {string} outcome the unified outcome of the order book
     * @returns {object} an [order book structure](https://docs.ccxt.com/#/?id=order-book-structure)
     */
    public Object parseWeiOrderBook(Object response, Object outcome)
    {
        Object rawBids = (java.util.List<Object>)(this.safeList(response, "bids", new java.util.ArrayList<Object>(java.util.Arrays.asList())));
        Object rawAsks = (java.util.List<Object>)(this.safeList(response, "asks", new java.util.ArrayList<Object>(java.util.Arrays.asList())));
        Object bids = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawBids)); i++)
        {
            Object row = Helpers.GetValue(rawBids, i);
            Object rowPrice = Precise.stringDiv(this.safeString(row, 0), "1000000000000000000");
            Object rowAmount = Precise.stringDiv(this.safeString(row, 1), "1000000000000000000");
            ((java.util.List<Object>)bids).add(new java.util.ArrayList<Object>(java.util.Arrays.asList(this.parseNumber(rowPrice), this.parseNumber(rowAmount))));
        }
        Object asks = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawAsks)); i++)
        {
            Object row = Helpers.GetValue(rawAsks, i);
            Object rowPrice = Precise.stringDiv(this.safeString(row, 0), "1000000000000000000");
            Object rowAmount = Precise.stringDiv(this.safeString(row, 1), "1000000000000000000");
            ((java.util.List<Object>)asks).add(new java.util.ArrayList<Object>(java.util.Arrays.asList(this.parseNumber(rowPrice), this.parseNumber(rowAmount))));
        }
        Object timestamp = this.milliseconds();
        return new java.util.HashMap<String, Object>() {{
            put( "outcome", outcome );
            put( "bids", MyriadCore.this.sortBy(bids, 0, true) );
            put( "asks", MyriadCore.this.sortBy(asks, 0) );
            put( "timestamp", timestamp );
            put( "datetime", MyriadCore.this.iso8601(timestamp) );
            put( "nonce", null );
        }};
    }

    /**
     * @method
     * @name myriad#fetchOHLCV
     * @description fetches price history for an outcome from the price_charts bucket embedded in the market response
     * @see https://docs.myriad.markets/builders/myriad-api-reference
     * @param {string} outcome unified outcome like TRUMP_WIN:YES or an outcome id
     * @param {string} timeframe mapped to the closest available chart bucket (24h, 7d or 30d)
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum number of candles to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {int[][]} a list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object outcome, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1d");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadOutcomes()).join();
            Object outcomeObj = this.outcome(outcome);
            Object outcomeInfo = this.safeDict(outcomeObj, "info", new java.util.HashMap<String, Object>() {{}});
            Object networkId = this.safeString(Helpers.GetValue(outcomeObj, "info"), "networkId");
            Object marketId = this.safeString(Helpers.GetValue(outcomeObj, "info"), "marketId");
            Object outcomeId = this.safeString(outcomeInfo, "outcomeId", this.safeString(outcomeInfo, "id"));
            Object outcomeTitle = this.safeString(outcomeInfo, "outcomeLabel", this.safeString(outcomeInfo, "label", this.safeString(outcomeInfo, "title")));
            Object bucketKey = this.safeString(this.timeframes, timeframe, "30d");
            Object response = (this.myriadPublicGetMarketsId(this.extend(new java.util.HashMap<String, Object>() {{
                put( "id", marketId );
                put( "network_id", networkId );
            }}, parameters))).join();
            //
            //     {
            //         "id": "164",
            //         "networkId": "2741",
            //         "slug": "trump-out-as-president-2027",
            //         "title": "Will Trump cease to be President before 2027?",
            //         "state": "open",
            //         "outcomes": [
            //             {
            //                 "id": "0",
            //                 "outcomeId": "0",
            //                 "title": "YES",
            //                 "label": "YES",
            //                 "price": 0.42,
            //                 "priceChange24h": -0.02
            //             }
            //         ],
            //         "price_charts": {
            //             "24h": {
            //                 "timeframe": "24h",
            //                 "prices": [
            //                     {
            //                         "timestamp": 1705318200,
            //                         "open": 0.40,
            //                         "high": 0.45,
            //                         "low": 0.39,
            //                         "close": 0.42,
            //                         "price": 0.42,
            //                         "value": 0.42
            //                     }
            //                 ]
            //             },
            //             "7d": {...},
            //             "30d": {...}
            //         }
            //     }
            //
            Object outcomes = (java.util.List<Object>)(this.safeList(response, "outcomes", new java.util.ArrayList<Object>(java.util.Arrays.asList())));
            Object selectedOutcome = null;
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(outcomes)); i++)
            {
                Object oc = Helpers.GetValue(outcomes, i);
                Object currentId = this.safeString(oc, "id", this.safeString(oc, "outcomeId"));
                Object currentTitle = this.safeString(oc, "title", this.safeString(oc, "label"));
                if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(outcomeId, null))) && Helpers.isTrue((Helpers.isEqual(currentId, outcomeId)))))
                {
                    selectedOutcome = oc;
                    break;
                }
                if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(selectedOutcome, null))) && Helpers.isTrue((!Helpers.isEqual(outcomeTitle, null)))) && Helpers.isTrue((Helpers.isEqual(currentTitle, outcomeTitle)))))
                {
                    selectedOutcome = oc;
                }
            }
            // price_charts is a list of { timeframe, prices } buckets, with a dict variant on some deployments
            Object chart = null;
            Object chartsList = this.safeList(selectedOutcome, "price_charts");
            if (Helpers.isTrue(!Helpers.isEqual(chartsList, null)))
            {
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(chartsList)); i++)
                {
                    Object chartObj = Helpers.GetValue(chartsList, i);
                    if (Helpers.isTrue(Helpers.isEqual(this.safeString(chartObj, "timeframe"), bucketKey)))
                    {
                        chart = chartObj;
                        break;
                    }
                }
            } else
            {
                Object chartsDict = this.safeDict(selectedOutcome, "price_charts", new java.util.HashMap<String, Object>() {{}});
                chart = this.safeValue(chartsDict, bucketKey);
            }
            Object pointsList = this.safeList(chart, "prices", this.safeList(chart, "data", ((Object)chart)));
            Object points = ((Helpers.isTrue((!Helpers.isEqual(pointsList, null))))) ? pointsList : new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object pointsLength = Helpers.getArrayLength(points);
            if (Helpers.isTrue(Helpers.isEqual(pointsLength, 0)))
            {
                Object priceCharts = this.safeDict(response, "price_charts", new java.util.HashMap<String, Object>() {{}});
                Object bucket = this.safeValue(priceCharts, bucketKey, new java.util.HashMap<String, Object>() {{}});
                points = (java.util.List<Object>)(this.safeList(bucket, outcomeId, this.safeList(bucket, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()))));
            }
            Object usablePoints = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(points)); i++)
            {
                Object point = Helpers.GetValue(points, i);
                Object pointOpen = this.safeNumber(point, "open");
                Object pointPrice = this.safeNumber(point, "price", this.safeNumber(point, "value"));
                Object pointTs = this.safeInteger(point, "timestamp");
                if (Helpers.isTrue(Helpers.isTrue((Helpers.isTrue((!Helpers.isEqual(pointOpen, null))) || Helpers.isTrue((!Helpers.isEqual(pointPrice, null))))) && Helpers.isTrue((!Helpers.isEqual(pointTs, null)))))
                {
                    ((java.util.List<Object>)usablePoints).add(point);
                }
            }
            return this.parseOHLCVs(usablePoints, outcomeObj, timeframe, since, limit);
        });

    }

    /**
     * @ignore
     * @method
     * @name myriad#parseOHLCV
     * @description parses a single myriad price chart data point into an ohlcv tuple
     * @param {object} ohlcv the raw price chart data point
     * @param {object} [market] the outcome object the candle belongs to
     * @returns {int[]} a candle ordered as timestamp, open, high, low, close, volume
     */
    public Object parseOHLCV(Object ohlcv, Object... optionalArgs)
    {
        //
        //     {
        //         "timestamp": 1705318200,
        //         "open": 0.40,
        //         "high": 0.45,
        //         "low": 0.39,
        //         "close": 0.42,
        //         "price": 0.42,
        //         "value": 0.42
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object open = this.safeNumber(ohlcv, "open");
        Object high = this.safeNumber(ohlcv, "high");
        Object low = this.safeNumber(ohlcv, "low");
        Object close = this.safeNumber(ohlcv, "close");
        Object price = this.safeNumber(ohlcv, "price", this.safeNumber(ohlcv, "value")); // fallback single-value tick
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeTimestamp(ohlcv, "timestamp"), ((Helpers.isTrue((!Helpers.isEqual(open, null))))) ? open : price, ((Helpers.isTrue((!Helpers.isEqual(high, null))))) ? high : price, ((Helpers.isTrue((!Helpers.isEqual(low, null))))) ? low : price, ((Helpers.isTrue((!Helpers.isEqual(close, null))))) ? close : price, 0));
    }

    /**
     * @method
     * @name myriad#fetchTickers
     * @description fetches tickers for multiple outcomes, grouping requested outcomes by their parent market to fetch each market only once
     * @see https://docs.myriad.markets/builders/myriad-api-reference
     * @param {string[]} [outcomes] unified outcomes, refreshes the markets listing and returns tickers for all outcomes when omitted
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a dictionary of [ticker structures](https://docs.ccxt.com/#/?id=ticker-structure) indexed by outcome
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTickers(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object outcomes = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadOutcomes()).join();
            Object result = new java.util.HashMap<String, Object>() {{}};
            if (Helpers.isTrue(Helpers.isEqual(outcomes, null)))
            {
                Object rawMarkets = (this.fetchRawMarketsList(parameters)).join();
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawMarkets)); i++)
                {
                    Object raw = Helpers.GetValue(rawMarkets, i);
                    Object m = this.parseMyriadMarket(raw);
                    Object outcomesList = (java.util.List<Object>)(this.safeList(m, "outcomes", new java.util.ArrayList<Object>(java.util.Arrays.asList())));
                    for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(outcomesList)); j++)
                    {
                        Object ticker = this.parseTicker(raw, Helpers.GetValue(outcomesList, j));
                        Object symbolKey = this.safeString(ticker, "outcome");
                        if (Helpers.isTrue(!Helpers.isEqual(symbolKey, null)))
                        {
                            Helpers.addElementToObject(result, symbolKey, ticker);
                        }
                    }
                }
                return result;
            }
            // group target outcomes by their parent market to fetch each market only once
            Object outcomesByMarket = new java.util.HashMap<String, Object>() {{}};
            Object marketKeys = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(outcomes)); i++)
            {
                Object outcomeObj = this.outcome(Helpers.GetValue(outcomes, i));
                Object info = this.safeDict(outcomeObj, "info", new java.util.HashMap<String, Object>() {{}});
                Object networkId = this.safeString(info, "networkId");
                Object marketId = this.safeString(info, "marketId");
                Object key = Helpers.add(Helpers.add(networkId, ":"), marketId);
                if (!Helpers.isTrue((Helpers.inOp(outcomesByMarket, key))))
                {
                    Helpers.addElementToObject(outcomesByMarket, key, new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                    ((java.util.List<Object>)marketKeys).add(key);
                }
                // reassign after push, plain mutation through a local is lost in transpiled php (arrays are value types there)
                Object grouped = Helpers.GetValue(outcomesByMarket, key);
                ((java.util.List<Object>)grouped).add(outcomeObj);
                Helpers.addElementToObject(outcomesByMarket, key, grouped);
            }
            Object promises = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(marketKeys)); i++)
            {
                Object key = Helpers.GetValue(marketKeys, i);
                Object grouped = (java.util.List<Object>)(Helpers.GetValue(outcomesByMarket, key));
                Object firstOutcome = Helpers.GetValue(grouped, 0);
                Object info = this.safeDict(firstOutcome, "info", new java.util.HashMap<String, Object>() {{}});
                ((java.util.List<Object>)promises).add(this.myriadPublicGetMarketsId(this.extend(new java.util.HashMap<String, Object>() {{
                    put( "id", MyriadCore.this.safeString(info, "marketId") );
                    put( "network_id", MyriadCore.this.safeString(info, "networkId") );
                }}, parameters)));
            }
            Object responses = (Helpers.promiseAll(promises)).join();
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(marketKeys)); i++)
            {
                Object key = Helpers.GetValue(marketKeys, i);
                Object response = Helpers.GetValue(responses, i);
                Object grouped = (java.util.List<Object>)(Helpers.GetValue(outcomesByMarket, key));
                for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(grouped)); j++)
                {
                    Object outcomeObj = Helpers.GetValue(grouped, j);
                    Object ticker = this.parseTicker(response, outcomeObj);
                    Object symbolKey = this.safeString(ticker, "outcome");
                    if (Helpers.isTrue(!Helpers.isEqual(symbolKey, null)))
                    {
                        Helpers.addElementToObject(result, symbolKey, ticker);
                    }
                }
            }
            return result;
        });

    }

    /**
     * @method
     * @name myriad#fetchTrades
     * @description fetches recent public trades for a single outcome from the market action feed
     * @see https://docs.myriad.markets/builders/myriad-api-reference
     * @param {string} outcome unified outcome like TRUMP_WIN:YES or an outcome id
     * @param {int} [since] timestamp in ms of the earliest trade to fetch
     * @param {int} [limit] the maximum number of trades to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [trade structures](https://docs.ccxt.com/#/?id=public-trades)
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTrades(Object outcome, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object since = Helpers.getArg(optionalArgs, 0, null);
            Object limit = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            (this.loadOutcomes()).join();
            Object outcomeObj = this.outcome(outcome);
            Object info = this.safeDict(outcomeObj, "info", new java.util.HashMap<String, Object>() {{}});
            Object networkId = this.safeString(info, "networkId");
            Object marketId = this.safeString(info, "marketId");
            Object outcomeId = this.safeString(info, "outcomeId");
            Object request = new java.util.HashMap<String, Object>() {{
                put( "id", marketId );
                put( "network_id", networkId );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit);
            }
            Object response = (this.myriadPublicGetMarketsIdEvents(this.extend(request, parameters))).join();
            //
            //     {
            //         "data": [
            //             {
            //                 "user": "0xAE7Bfff784EeEe7812D6527B72c77A7Ed773Ed9D",
            //                 "action": "buy",
            //                 "marketTitle": "BNB candles from 10:00 to 10:05 UTC",
            //                 "marketSlug": "bnb-candles-from-10-00-to-10-05-utc",
            //                 "marketId": 218,
            //                 "networkId": 56,
            //                 "outcomeTitle": "More Green",
            //                 "outcomeId": 0,
            //                 "shares": 500,
            //                 "value": 500,
            //                 "timestamp": 1761645928,
            //                 "blockNumber": 66193433,
            //                 "token": "0x55d398326f99059fF775485246999027B3197955",
            //                 "txId": "0x3c81447bd6e5c4c80a6e1425383c0b044ddcb1525d09027c2b371ff84f9b9fa0"
            //             }
            //         ]
            //     }
            //
            Object rowsList = this.safeList(response, "data", ((Object)response));
            Object rows = ((Helpers.isTrue((!Helpers.isEqual(rowsList, null))))) ? rowsList : new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object trades = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rows)); i++)
            {
                Object row = Helpers.GetValue(rows, i);
                Object action = this.safeString(row, "action");
                if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(action, "buy"))) && Helpers.isTrue((!Helpers.isEqual(action, "sell")))))
                {
                    continue;
                }
                Object rowOutcomeId = this.safeString(row, "outcomeId");
                if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(outcomeId, null))) && Helpers.isTrue((!Helpers.isEqual(rowOutcomeId, outcomeId)))))
                {
                    continue;
                }
                ((java.util.List<Object>)trades).add(row);
            }
            return this.parsePredictionTrades(trades, outcomeObj, since, limit);
        });

    }

    /**
     * @ignore
     * @method
     * @name myriad#parseTrade
     * @description parses a raw market action feed row into a unified trade object
     * @param {object} trade the raw action feed row
     * @param {object} [market] the outcome object the trade belongs to
     * @returns {object} a [trade structure](https://docs.ccxt.com/#/?id=public-trades)
     */
    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeTimestamp(trade, "timestamp");
        Object amountStr = this.safeString(trade, "shares");
        Object costStr = this.safeString(trade, "value");
        Object priceStr = null;
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(amountStr, null))) && Helpers.isTrue((!Helpers.isEqual(costStr, null)))) && !Helpers.isTrue(Precise.stringEq(amountStr, "0"))))
        {
            priceStr = Precise.stringDiv(costStr, amountStr);
        }
        final Object finalPriceStr = priceStr;
        final Object finalAmountStr = amountStr;
        final Object finalCostStr = costStr;
        return this.safePredictionTrade(new java.util.HashMap<String, Object>() {{
            put( "id", MyriadCore.this.safeString(trade, "txId") );
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", MyriadCore.this.iso8601(timestamp) );
            put( "outcome", MyriadCore.this.safeString(market, "outcome") );
            put( "outcomeId", MyriadCore.this.safeString(market, "id") );
            put( "label", MyriadCore.this.safeString(market, "label") );
            put( "market", MyriadCore.this.safeString(market, "market") );
            put( "order", null );
            put( "type", null );
            put( "side", MyriadCore.this.safeString(trade, "action") );
            put( "takerOrMaker", "taker" );
            put( "price", MyriadCore.this.parseNumber(finalPriceStr) );
            put( "amount", MyriadCore.this.parseNumber(finalAmountStr) );
            put( "cost", MyriadCore.this.parseNumber(finalCostStr) );
            put( "fee", null );
        }}, market);
    }

    /**
     * @method
     * @name myriad#fetchEvents
     * @description fetches prediction-market events matching the given search terms (or all open markets when omitted) and caches their markets and outcomes on the instance
     * @see https://docs.myriad.markets/builders/myriad-api-reference
     * @param {object} [params] extra exchange-specific parameters
     * @param {string} [params.query] a single search term; when omitted (and no queries) returns the events cached by loadMarkets (capped by options.fetchMarketsLimit)
     * @param {string[]} [params.queries] multiple search terms (alternative to query)
     * @param {int} [params.limit] maximum number of markets per query, defaults to 50
     * @param {string} [params.state] 'open', 'closed' or 'resolved', defaults to 'open'
     * @returns {object[]} an array of event structures
     */
    public java.util.concurrent.CompletableFuture<Object> fetchEvents(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            this.requireEventQuery(parameters);
            Object queries = this.parseSearchQueries(parameters);
            Object rest = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("query", "queries", "sort", "searchIn", "eventId", "slug", "status")));
            Object queriesLength = Helpers.getArrayLength(queries);
            if (Helpers.isTrue(Helpers.isEqual(queriesLength, 0)))
            {
                this.populateOutcomes();
                // hoist Object.values to a local — inline as a call argument breaks the php regex transpiler
                Object existingEvents = (java.util.List<Object>)(Helpers.objectValues(this.events));
                return this.applyEventFetchParams(existingEvents, parameters, queries);
            }
            Object rawMarkets = (this.fetchRawMarketsBySearch(queries, rest)).join();
            if (!Helpers.isTrue(this.events))
            {
                this.events = new java.util.HashMap<String, Object>() {{}};
            }
            if (!Helpers.isTrue(this.markets))
            {
                this.markets = this.createSafeDictionary();
            }
            Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawMarkets)); i++)
            {
                Object raw = Helpers.GetValue(rawMarkets, i);
                Object m = this.parseMyriadMarket(raw);
                Helpers.addElementToObject(this.markets, ((String)Helpers.GetValue(m, "symbol")), m);
                Object ev = this.parseMarketToEvent(raw, m);
                Object evKey = this.safeString(ev, "event");
                if (Helpers.isTrue(!Helpers.isEqual(evKey, null)))
                {
                    Helpers.addElementToObject(this.events, evKey, ev);
                    ((java.util.List<Object>)result).add(ev);
                }
            }
            this.populateOutcomes();
            return this.applyEventFetchParams(result, parameters, queries);
        });

    }

    /**
     * @ignore
     * @method
     * @name myriad#parseEvent
     * @description parses a raw myriad question object into the unified event shape with a nested markets list
     * @param {object} rawEvent the raw myriad question object
     * @returns {object} an event structure
     */
    public Object parseEvent(Object rawEvent)
    {
        Object questionSlug = this.safeString(rawEvent, "slug", this.safeString(rawEvent, "id"));
        Object rawMarkets = (java.util.List<Object>)(this.safeList(rawEvent, "markets", new java.util.ArrayList<Object>(java.util.Arrays.asList())));
        Object marketsList = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawMarkets)); i++)
        {
            Object rawMarket = Helpers.GetValue(rawMarkets, i);
            ((java.util.List<Object>)marketsList).add(this.parseMyriadMarket(rawMarket, questionSlug));
        }
        Object endDate = this.safeString(rawEvent, "expiresAt", this.safeString(rawEvent, "endDate"));
        return this.extend(rawEvent, new java.util.HashMap<String, Object>() {{
            put( "id", MyriadCore.this.safeString(rawEvent, "id") );
            put( "slug", questionSlug );
            put( "event", ((Helpers.isTrue(questionSlug))) ? MyriadCore.this.shortenSlug(questionSlug) : null );
            put( "title", MyriadCore.this.safeString(rawEvent, "title") );
            put( "description", MyriadCore.this.safeString(rawEvent, "description") );
            put( "markets", marketsList );
            put( "volume", MyriadCore.this.safeNumber2(rawEvent, "volumeNotional24h", "volume24h") );
            put( "liquidity", MyriadCore.this.safeNumber(rawEvent, "liquidity") );
            put( "url", MyriadCore.this.safeString(rawEvent, "url") );
            put( "image", MyriadCore.this.safeString(rawEvent, "imageUrl", MyriadCore.this.safeString(rawEvent, "image")) );
            put( "active", MyriadCore.this.safeBool(rawEvent, "active") );
            put( "resolved", MyriadCore.this.safeBool(rawEvent, "resolved", false) );
            put( "category", MyriadCore.this.safeString(rawEvent, "category") );
            put( "tags", MyriadCore.this.safeList(rawEvent, "tags") );
            put( "created", MyriadCore.this.parse8601(MyriadCore.this.safeString(rawEvent, "createdAt")) );
            put( "createdDatetime", MyriadCore.this.safeString(rawEvent, "createdAt") );
            put( "end", ((Helpers.isTrue(endDate))) ? MyriadCore.this.parse8601(endDate) : null );
            put( "endDatetime", endDate );
            put( "lastUpdatedAt", MyriadCore.this.parse8601(MyriadCore.this.safeString(rawEvent, "updatedAt")) );
            put( "resolutionSource", MyriadCore.this.safeString(rawEvent, "resolutionSource") );
            put( "info", rawEvent );
        }});
    }

    public Object requestId(Object url)
    {
        Object existing = this.safeValue(this.options, "requestId");
        if (Helpers.isTrue(Helpers.isEqual(existing, null)))
        {
            Helpers.addElementToObject(this.options, "requestId", this.createSafeDictionary());
        }
        Object options = Helpers.GetValue(this.options, "requestId");
        Object previousValue = this.safeInteger(options, url, 0);
        Object newValue = this.sum(previousValue, 1);
        Helpers.addElementToObject(Helpers.GetValue(this.options, "requestId"), url, newValue);
        return newValue;
    }

    public Object fromWei(Object wei)
    {
        if (Helpers.isTrue(Helpers.isEqual(wei, null)))
        {
            return null;
        }
        return this.parseNumber(Precise.stringDiv(wei, "1000000000000000000"));
    }

    public Object marketOutcomeToSymbol(Object networkId, Object marketId, Object outcomeId)
    {
        // guard the ids before concatenating: a missing id would crash on string + None in Python/PHP
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(networkId, null))) || Helpers.isTrue((Helpers.isEqual(marketId, null)))) || Helpers.isTrue((Helpers.isEqual(outcomeId, null)))))
        {
            return null;
        }
        Object ocId = Helpers.add(Helpers.add(Helpers.add(Helpers.add(networkId, ":"), marketId), "/"), outcomeId);
        Object outcomeObj = this.safeDict(this.outcomes_by_id, ocId);
        return this.safeString(outcomeObj, "outcome");
    }

    public java.util.concurrent.CompletableFuture<Object> connectCentrifugo(Object url)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            // Centrifugo requires an anonymous connect command before any subscribe. This sends it once per
            // connection and resolves when the connect reply arrives (see handleCentrifugoFrame). The base
            // clears client.subscriptions on reconnect, so an absent 'connect' marker means a fresh handshake.
            Client client = this.client(url);
            Object connectSent = this.safeValue(client.subscriptions, "connect");
            if (Helpers.isTrue(Helpers.isEqual(connectSent, null)))
            {
                Helpers.addElementToObject(this.options, "wsConnected", false);
                Object requestId = this.requestId(url);
                // give the anonymous connect a name so the params object is non-empty (PHP serialises an
                // empty array as a JSON array, which Centrifugo rejects)
                Object connectMsg = new java.util.HashMap<String, Object>() {{
                    put( "connect", new java.util.HashMap<String, Object>() {{
                        put( "name", "ccxt" );
                    }} );
                    put( "id", requestId );
                }};
                return (this.watch(url, "centrifugoConnected", connectMsg, "connect", null)).join();
            }
            if (Helpers.isTrue(this.safeBool(this.options, "wsConnected", false)))
            {
                // the connect reply already arrived on this connection — safe to subscribe immediately
                return null;
            }
            // connect is in flight (sent by a concurrent subscribe) — wait on the shared reply future
            return client.future("centrifugoConnected").getFuture().join();
        });

    }

    public java.util.concurrent.CompletableFuture<Object> pong(Client client, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            // Centrifugo server pings are empty frames; reply with the same empty frame to keep the link alive
            Object message = Helpers.getArg(optionalArgs, 0, null);
            (client.send("{}")).join();
            return null;
        });

    }

    public java.util.concurrent.CompletableFuture<Object> subscribeMyriadChannel(Object messageHash, Object channel, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object url = this.safeString(Helpers.GetValue(this.urls, "api"), "ws");
            // finish the connect handshake first so the subscribe frame is sent after the connect reply
            (this.connectCentrifugo(url)).join();
            Object requestId = this.requestId(url);
            Object subscribeMsg = new java.util.HashMap<String, Object>() {{
                put( "subscribe", new java.util.HashMap<String, Object>() {{
                    put( "channel", channel );
                }} );
                put( "id", requestId );
            }};
            return (this.watch(url, messageHash, subscribeMsg, channel, null)).join();
        });

    }

    public void handleMessage(Client client, Object message)
    {
        // Centrifugo packs several commands per frame joined by \n; a multi-command frame fails the
        // base JSON.parse and arrives here as a raw string, a single command arrives already parsed
        if (Helpers.isTrue((message instanceof String)))
        {
            Object lines = Helpers.split(message, "\n");
            Object linesLength = Helpers.getArrayLength(lines);
            for (var i = 0; Helpers.isLessThan(i, linesLength); i++)
            {
                Object line = Helpers.GetValue(lines, i);
                if (Helpers.isTrue(Helpers.isGreaterThan(((String)line).length(), 0)))
                {
                    Object parsed = Helpers.parseJson(line);
                    this.handleCentrifugoFrame(client, parsed);
                }
            }
            return;
        }
        this.handleCentrifugoFrame(client, message);
    }

    public void handleCentrifugoFrame(Client client, Object msg)
    {
        Object keys = Helpers.objectKeys(msg);
        Object keysLength = Helpers.getArrayLength(keys);
        if (Helpers.isTrue(Helpers.isEqual(keysLength, 0)))
        {
            this.spawn(() -> { try { this.pong(client, msg); } catch(Exception _e) { throw new RuntimeException(_e); } });
            return;
        }
        Object connectReply = this.safeDict(msg, "connect");
        if (Helpers.isTrue(!Helpers.isEqual(connectReply, null)))
        {
            // connect acknowledged — unblock connectCentrifugo so channel subscribes can be sent
            Helpers.addElementToObject(this.options, "wsConnected", true);
            client.resolve(true, "centrifugoConnected");
            return;
        }
        Object push = this.safeDict(msg, "push");
        if (Helpers.isTrue(Helpers.isEqual(push, null)))
        {
            return;
        }
        Object channel = this.safeString(push, "channel");
        if (Helpers.isTrue(Helpers.isEqual(channel, null)))
        {
            return;
        }
        Object pub = this.safeDict(push, "pub", new java.util.HashMap<String, Object>() {{}});
        Object data = this.safeDict(pub, "data", new java.util.HashMap<String, Object>() {{}});
        Object parts = Helpers.split(channel, ":");
        Object channelType = this.safeString(parts, 0);
        if (Helpers.isTrue(Helpers.isEqual(channelType, "orderbook")))
        {
            this.handleOrderBook(client, data);
        } else if (Helpers.isTrue(Helpers.isEqual(channelType, "trades")))
        {
            this.handleTrades(client, data);
        } else if (Helpers.isTrue(Helpers.isEqual(channelType, "prices")))
        {
            this.handleTicker(client, data);
        } else if (Helpers.isTrue(Helpers.isEqual(channelType, "orders")))
        {
            this.handleOrder(client, data);
        } else if (Helpers.isTrue(Helpers.isEqual(channelType, "positions")))
        {
            this.handlePosition(client, data);
        }
    }

    /**
     * @method
     * @name myriad#watchOrderBook
     * @description streams the order book for an outcome over the Centrifugo websocket; the channel is delta-only so the book is seeded from the REST snapshot
     * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da82810581f8d2c8be2364fa
     * @param {string} outcome unified outcome
     * @param {int} [limit] the maximum number of order book entries to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order book structure](https://docs.ccxt.com/#/?id=order-book-structure)
     */
    public java.util.concurrent.CompletableFuture<Object> watchOrderBook(Object outcome, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object limit = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadOutcomes()).join();
            Object outcomeObj = this.outcome(outcome);
            Object info = this.safeDict(outcomeObj, "info", new java.util.HashMap<String, Object>() {{}});
            Object networkId = this.safeString(info, "networkId");
            Object marketId = this.safeString(info, "marketId");
            Object sym = this.safeOutcomeSymbol(outcome, outcomeObj);
            Object channel = Helpers.add(Helpers.add(Helpers.add("orderbook:", networkId), ":"), marketId);
            Object messageHash = Helpers.add("orderbook::", sym);
            Object url = this.safeString(Helpers.GetValue(this.urls, "api"), "ws");
            // finish the connect handshake first so the client exists and the subscribe follows the connect reply
            (this.connectCentrifugo(url)).join();
            Client client = this.client(url);
            Object isNewSubscription = Helpers.isEqual(this.safeValue(client.subscriptions, channel), null);
            if (Helpers.isTrue(isNewSubscription))
            {
                // the channel only streams deltas, so (re)seed the live book from the REST snapshot on a
                // fresh subscription (first call or after a reconnect that cleared client.subscriptions)
                (this.seedOrderBook(outcome, sym, limit)).join();
            }
            Object requestId = this.requestId(url);
            Object subscribeMsg = new java.util.HashMap<String, Object>() {{
                put( "subscribe", new java.util.HashMap<String, Object>() {{
                    put( "channel", channel );
                }} );
                put( "id", requestId );
            }};
            Object future = this.watch(url, messageHash, subscribeMsg, channel, null);
            if (Helpers.isTrue(isNewSubscription))
            {
                // return the freshly-seeded book immediately instead of blocking until the next delta
                client.resolve(Helpers.GetValue(this.orderbooks, sym), messageHash);
            }
            Object orderbook = ((io.github.ccxt.ws.Future)future).getFuture().join();
            return Helpers.callDynamically(orderbook, "limit", new Object[]{});
        });

    }

    public java.util.concurrent.CompletableFuture<Object> seedOrderBook(Object outcome, Object sym, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            // the order book channel streams deltas only, so seed the live book from the REST snapshot
            Object limit = Helpers.getArg(optionalArgs, 0, null);
            Object snapshot = (this.fetchOrderBook(outcome, limit)).join();
            Object orderbook = this.orderBook(new java.util.HashMap<String, Object>() {{}});
            Helpers.callDynamically(orderbook, "reset", new Object[]{snapshot});
            Helpers.addElementToObject(this.orderbooks, sym, orderbook);
            return null;
        });

    }

    public void handleOrderBook(Client client, Object data)
    {
        Object networkId = this.safeString(data, "networkId");
        Object marketId = this.safeString(data, "marketId");
        Object ts = this.safeInteger(data, "ts");
        Object changes = this.safeList(data, "changes", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object changesLength = Helpers.getArrayLength(changes);
        Object updated = new java.util.HashMap<String, Object>() {{}};
        for (var i = 0; Helpers.isLessThan(i, changesLength); i++)
        {
            Object change = Helpers.GetValue(changes, i);
            Object outcomeId = this.safeString(change, "outcome");
            Object sym = this.marketOutcomeToSymbol(networkId, marketId, outcomeId);
            if (Helpers.isTrue(Helpers.isEqual(sym, null)))
            {
                continue;
            }
            if (Helpers.isTrue(Helpers.isEqual(this.safeValue(this.orderbooks, sym), null)))
            {
                continue;
            }
            Object orderbook = Helpers.GetValue(this.orderbooks, sym);
            Object price = this.fromWei(this.safeString(change, "price"));
            Object amount = this.fromWei(this.safeString(change, "amount"));
            Object sideStr = this.safeString(change, "side");
            Object bookSide = ((Helpers.isTrue((Helpers.isEqual(sideStr, "bid"))))) ? Helpers.GetValue(orderbook, "bids") : Helpers.GetValue(orderbook, "asks");
            Helpers.callDynamically(bookSide, "storeArray", new Object[]{new java.util.ArrayList<Object>(java.util.Arrays.asList(price, amount))});
            Helpers.addElementToObject(orderbook, "timestamp", ts);
            Helpers.addElementToObject(orderbook, "datetime", this.iso8601(ts));
            Helpers.addElementToObject(updated, sym, true);
        }
        Object updatedSymbols = Helpers.objectKeys(updated);
        Object updatedLength = Helpers.getArrayLength(updatedSymbols);
        for (var k = 0; Helpers.isLessThan(k, updatedLength); k++)
        {
            Object sym = Helpers.GetValue(updatedSymbols, k);
            client.resolve(Helpers.GetValue(this.orderbooks, sym), Helpers.add("orderbook::", sym));
        }
    }

