    /**
     * @method
     * @name myriad#watchTickers
     * @description streams best bid/ask/last for several outcomes over the Centrifugo prices channels
     * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da82810581f8d2c8be2364fa
     * @param {string[]} outcomes unified outcomes to watch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a dict of [ticker structures](https://docs.ccxt.com/#/?id=ticker-structure) indexed by outcome
     */
    public java.util.concurrent.CompletableFuture<Object> watchTickers(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object outcomes = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadOutcomes()).join();
            if (Helpers.isTrue(Helpers.isEqual(outcomes, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " watchTickers() requires a list of outcomes (the prices channel is per-market)")) ;
            }
            Object symbolsLength = Helpers.getArrayLength(outcomes);
            Object url = this.safeString(Helpers.GetValue(this.urls, "api"), "ws");
            (this.connectCentrifugo(url)).join();
            Client client = this.client(url);
            Object seenChannels = new java.util.HashMap<String, Object>() {{}};
            Object resolvedSymbols = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, symbolsLength); i++)
            {
                Object outcomeObj = this.outcome(Helpers.GetValue(outcomes, i));
                Object info = this.safeDict(outcomeObj, "info", new java.util.HashMap<String, Object>() {{}});
                Object networkId = this.safeString(info, "networkId");
                Object marketId = this.safeString(info, "marketId");
                Object channel = Helpers.add(Helpers.add(Helpers.add("prices:", networkId), ":"), marketId);
                ((java.util.List<Object>)resolvedSymbols).add(this.safeOutcomeSymbol(Helpers.GetValue(outcomes, i), outcomeObj));
                if (Helpers.isTrue(Helpers.isEqual(this.safeValue(seenChannels, channel), null)))
                {
                    Helpers.addElementToObject(seenChannels, channel, true);
                    Object requestId = this.requestId(url);
                    Object subscribeMsg = new java.util.HashMap<String, Object>() {{
                        put( "subscribe", new java.util.HashMap<String, Object>() {{
                            put( "channel", channel );
                        }} );
                        put( "id", requestId );
                    }};
                    this.watch(url, "tickers", subscribeMsg, channel, null);
                }
            }
            Object tickers = client.future("tickers").getFuture().join();
            return this.filterByArray(tickers, "outcome", resolvedSymbols, true);
        });

    }

    /**
     * @method
     * @name myriad#watchOHLCV
     * @description streams OHLCV candles for an outcome, synthesised from the live trades channel
     * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da82810581f8d2c8be2364fa
     * @param {string} outcome unified outcome
     * @param {string} timeframe the length of each candle (e.g. '1m', '1h', '1d')
     * @param {int} [since] timestamp in ms of the earliest candle
     * @param {int} [limit] the maximum number of candles to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {int[][]} a list of [timestamp, open, high, low, close, volume] candles
     */
    public java.util.concurrent.CompletableFuture<Object> watchOHLCV(Object outcome, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            // Myriad has no OHLCV websocket channel, so build candles from the live trade stream
            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            Object trades = (this.watchTrades(outcome, since, limit, parameters)).join();
            Object ohlcvc = this.buildOHLCVC(trades, timeframe, 0, 2147483647);
            Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object ohlcvcLength = Helpers.getArrayLength(ohlcvc);
            for (var i = 0; Helpers.isLessThan(i, ohlcvcLength); i++)
            {
                Object candle = Helpers.GetValue(ohlcvc, i);
                ((java.util.List<Object>)result).add(new java.util.ArrayList<Object>(java.util.Arrays.asList(Helpers.GetValue(candle, 0), Helpers.GetValue(candle, 1), Helpers.GetValue(candle, 2), Helpers.GetValue(candle, 3), Helpers.GetValue(candle, 4), Helpers.GetValue(candle, 5))));
            }
            return this.filterBySinceLimit(result, since, limit, 0, true);
        });

    }

    public void handleTicker(Client client, Object data)
    {
        Object networkId = this.safeString(data, "networkId");
        Object marketId = this.safeString(data, "marketId");
        Object ts = this.safeInteger(data, "ts");
        Object outcomes = this.safeList(data, "outcomes", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object outcomesLength = Helpers.getArrayLength(outcomes);
        if (Helpers.isTrue(Helpers.isEqual(this.tickers, null)))
        {
            this.tickers = this.createSafeDictionary();
        }
        for (var i = 0; Helpers.isLessThan(i, outcomesLength); i++)
        {
            Object oc = Helpers.GetValue(outcomes, i);
            Object outcomeId = this.safeString(oc, "outcome");
            Object sym = this.marketOutcomeToSymbol(networkId, marketId, outcomeId);
            if (Helpers.isTrue(Helpers.isEqual(sym, null)))
            {
                continue;
            }
            Object market = this.safeMarket(sym);
            Object outcomeObj = this.safeOutcome(sym);
            Object last = this.fromWei(this.safeString(oc, "last"));
            final Object finalSym = sym;
            Object ticker = this.safePredictionTicker(new java.util.HashMap<String, Object>() {{
                put( "outcome", finalSym );
                put( "outcomeId", MyriadCore.this.safeString2(outcomeObj, "outcomeId", "id") );
                put( "label", MyriadCore.this.safeString(outcomeObj, "label") );
                put( "market", MyriadCore.this.safeString(outcomeObj, "market") );
                put( "timestamp", ts );
                put( "datetime", MyriadCore.this.iso8601(ts) );
                put( "high", null );
                put( "low", null );
                put( "bid", MyriadCore.this.fromWei(MyriadCore.this.safeString(oc, "bestBid")) );
                put( "bidVolume", null );
                put( "ask", MyriadCore.this.fromWei(MyriadCore.this.safeString(oc, "bestAsk")) );
                put( "askVolume", null );
                put( "vwap", null );
                put( "open", null );
                put( "close", last );
                put( "last", last );
                put( "previousClose", null );
                put( "change", null );
                put( "percentage", null );
                put( "average", null );
                put( "baseVolume", null );
                put( "quoteVolume", null );
                put( "info", oc );
            }}, market);
            Helpers.addElementToObject(this.tickers, sym, ticker);
            client.resolve(ticker, Helpers.add("ticker::", sym));
        }
        client.resolve(this.tickers, "tickers");
    }

    /**
     * @method
     * @name myriad#watchOrders
     * @description streams the wallet's order lifecycle updates over the Centrifugo orders channel
     * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da82810581f8d2c8be2364fa
     * @param {string} [outcome] unified outcome to filter by
     * @param {int} [since] timestamp in ms of the earliest order
     * @param {int} [limit] the maximum number of orders to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [order structures](https://docs.ccxt.com/#/?id=order-structure)
     */
    public java.util.concurrent.CompletableFuture<Object> watchOrders(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object outcome = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadOutcomes()).join();
            Object trader = this.walletAddressFromKeys();
            Object networkId = this.safeString(this.options, "defaultNetworkId", "56");
            if (Helpers.isTrue(!Helpers.isEqual(outcome, null)))
            {
                Object outcomeObj = this.outcome(outcome);
                Object info = this.safeDict(outcomeObj, "info", new java.util.HashMap<String, Object>() {{}});
                networkId = this.safeString(info, "networkId", networkId);
                outcome = this.safeOutcomeSymbol(outcome, outcomeObj);
            }
            Object channel = Helpers.add(Helpers.add(Helpers.add("orders:", networkId), ":"), trader);
            Object messageHash = "orders";
            Object orders = (this.subscribeMyriadChannel(messageHash, channel, parameters)).join();
            return this.filterByValueSinceLimit(orders, "outcome", outcome, since, limit, "timestamp", true);
        });

    }

    public void handleOrder(Client client, Object data)
    {
        if (Helpers.isTrue(Helpers.isEqual(this.orders, null)))
        {
            Object limit = this.safeInteger(this.options, "ordersLimit", 1000);
            this.orders = new ArrayCache.ArrayCacheByOutcomeById(((Number)limit).intValue());
        }
        Object networkId = this.safeString(data, "networkId");
        Object marketId = this.safeString(data, "marketId");
        Object outcomeId = this.safeString(data, "outcome");
        Object sym = this.marketOutcomeToSymbol(networkId, marketId, outcomeId);
        Object outcomeObj = this.safeOutcome(sym);
        Object price = this.fromWei(this.safeString(data, "price"));
        Object amount = this.fromWei(this.safeString(data, "amount"));
        Object filled = this.fromWei(this.safeString(data, "filledAmount"));
        Object status = this.parseOrderStatus(this.safeStringLower(data, "status"));
        Object tif = this.safeStringUpper(data, "timeInForce");
        Object isMarketTif = Helpers.isTrue((Helpers.isEqual(tif, "FOK"))) || Helpers.isTrue((Helpers.isEqual(tif, "FAK")));
        Object timestamp = this.parse8601(this.safeString2(data, "updatedAt", "createdAt"));
        final Object finalSym = sym;
        final Object finalTif = tif;
        Object parsed = this.safePredictionOrder(new java.util.HashMap<String, Object>() {{
            put( "id", MyriadCore.this.safeString(data, "orderHash") );
            put( "clientOrderId", null );
            put( "info", data );
            put( "timestamp", timestamp );
            put( "datetime", MyriadCore.this.iso8601(timestamp) );
            put( "outcome", finalSym );
            put( "outcomeId", MyriadCore.this.safeString2(outcomeObj, "outcomeId", "id") );
            put( "label", MyriadCore.this.safeString(outcomeObj, "label") );
            put( "market", MyriadCore.this.safeString(outcomeObj, "market") );
            put( "type", ((Helpers.isTrue(isMarketTif))) ? "market" : "limit" );
            put( "timeInForce", finalTif );
            put( "side", MyriadCore.this.safeStringLower(data, "side") );
            put( "price", price );
            put( "amount", amount );
            put( "filled", filled );
            put( "remaining", null );
            put( "average", null );
            put( "cost", null );
            put( "status", status );
            put( "fee", null );
            put( "trades", null );
        }});
        Object stored = this.orders;
        Helpers.callDynamically(stored, "append", new Object[]{parsed});
        client.resolve(stored, "orders");
        if (Helpers.isTrue(!Helpers.isEqual(sym, null)))
        {
            client.resolve(stored, Helpers.add("orders::", sym));
        }
    }

    /**
     * @method
     * @name myriad#watchPositions
     * @description streams the wallet's share-balance changes over the Centrifugo positions channel
     * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da82810581f8d2c8be2364fa
     * @param {string[]} [outcomes] unified outcomes to filter by
     * @param {int} [since] timestamp in ms of the earliest position update
     * @param {int} [limit] the maximum number of position updates to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [position structures](https://docs.ccxt.com/#/?id=position-structure)
     */
    public java.util.concurrent.CompletableFuture<Object> watchPositions(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object outcomes = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadOutcomes()).join();
            Object trader = this.walletAddressFromKeys();
            Object networkId = this.safeString(this.options, "defaultNetworkId", "56");
            Object channel = Helpers.add(Helpers.add(Helpers.add("positions:", networkId), ":"), trader);
            Object messageHash = "positions";
            Object url = this.safeString(Helpers.GetValue(this.urls, "api"), "ws");
            (this.connectCentrifugo(url)).join();
            Client client = this.client(url);
            Object isNewSubscription = Helpers.isEqual(this.safeValue(client.subscriptions, channel), null);
            if (Helpers.isTrue(isNewSubscription))
            {
                // the channel pushes only signed deltas; seed absolute share balances from REST so
                // handlePosition can maintain a running contracts figure
                (this.seedPositionBalances(trader)).join();
            }
            Object requestId = this.requestId(url);
            Object subscribeMsg = new java.util.HashMap<String, Object>() {{
                put( "subscribe", new java.util.HashMap<String, Object>() {{
                    put( "channel", channel );
                }} );
                put( "id", requestId );
            }};
            Object positions = (this.watch(url, messageHash, subscribeMsg, channel, null)).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                return positions;
            }
            return this.filterByOutcomesSinceLimit(positions, outcomes, since, limit, true);
        });

    }

    public java.util.concurrent.CompletableFuture<Object> seedPositionBalances(Object trader)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object positions = (this.fetchPositions(null, (Object) new java.util.HashMap<String, Object>() {{
                put( "address", trader );
            }})).join();
            Object balances = new java.util.HashMap<String, Object>() {{}};
            Object positionsLength = Helpers.getArrayLength(positions);
            for (var i = 0; Helpers.isLessThan(i, positionsLength); i++)
            {
                Object p = Helpers.GetValue(positions, i);
                Object id = this.safeString(p, "id");
                if (Helpers.isTrue(!Helpers.isEqual(id, null)))
                {
                    Helpers.addElementToObject(balances, id, this.numberToString(this.safeNumber(p, "contracts", 0)));
                }
            }
            Helpers.addElementToObject(this.options, "positionBalances", balances);
            return null;
        });

    }

    public void handlePosition(Client client, Object data)
    {
        if (Helpers.isTrue(Helpers.isEqual(this.positions, null)))
        {
            Object limit = this.safeInteger(this.options, "positionsLimit", 1000);
            this.positions = new ArrayCache.ArrayCacheByOutcomeById(((Number)limit).intValue());
        }
        Object networkId = this.safeString(data, "networkId");
        Object marketId = this.safeString(data, "marketId");
        Object outcomeId = this.safeString(data, "outcome");
        Object sym = this.marketOutcomeToSymbol(networkId, marketId, outcomeId);
        Object outcomeObj = this.safeOutcome(sym);
        Object ts = this.safeInteger(data, "ts");
        // the channel pushes a signed share delta per fill/redeem/split/merge (no absolute balance);
        // apply it to the REST-seeded balance keyed by outcome id to maintain a running contracts figure
        Object deltaStr = this.safeString(data, "delta", "0");
        Object firstChar = Helpers.slice(deltaStr, 0, 1);
        if (Helpers.isTrue(Helpers.isEqual(firstChar, "+")))
        {
            deltaStr = Helpers.slice(deltaStr, 1, null);
        }
        Object deltaShares = Precise.stringDiv(deltaStr, "1000000000000000000");
        Object contracts = null;
        Object posId = null;
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(networkId, null))) && Helpers.isTrue((!Helpers.isEqual(marketId, null)))) && Helpers.isTrue((!Helpers.isEqual(outcomeId, null)))))
        {
            posId = Helpers.add(Helpers.add(Helpers.add(Helpers.add(networkId, ":"), marketId), "/"), outcomeId);
            Object balances = this.safeDict(this.options, "positionBalances", new java.util.HashMap<String, Object>() {{}});
            Object prior = this.safeString(balances, posId, "0");
            Object updated = Precise.stringAdd(prior, deltaShares);
            Helpers.addElementToObject(balances, posId, updated);
            Helpers.addElementToObject(this.options, "positionBalances", balances);
            contracts = this.parseNumber(updated);
        }
        final Object finalPosId = posId;
        final Object finalContracts = contracts;
        Object parsed = this.safePredictionPosition(new java.util.HashMap<String, Object>() {{
            put( "info", data );
            put( "id", finalPosId );
            put( "outcome", sym );
            put( "outcomeId", finalPosId );
            put( "label", MyriadCore.this.safeString(outcomeObj, "label") );
            put( "market", MyriadCore.this.safeString(outcomeObj, "market") );
            put( "timestamp", ts );
            put( "datetime", MyriadCore.this.iso8601(ts) );
            put( "side", "long" );
            put( "contracts", finalContracts );
            put( "entryPrice", null );
            put( "markPrice", null );
            put( "notional", null );
            put( "collateral", null );
            put( "unrealizedPnl", null );
        }});
        Object stored = this.positions;
        Helpers.callDynamically(stored, "append", new Object[]{parsed});
        client.resolve(stored, "positions");
    }

    public Object walletAddressFromKeys()
    {
        // the orders/positions channels are keyed by the lowercase trader address (Centrifugo channels
        // are case-sensitive); lowercase here so the channel matches regardless of the address checksum.
        // check length too: an unset walletAddress is an empty string (not undefined) in some languages
        Object address = this.walletAddress;
        Object hasWallet = Helpers.isTrue((!Helpers.isEqual(address, null))) && Helpers.isTrue((Helpers.isGreaterThan(((String)this.walletAddress).length(), 0)));
        if (!Helpers.isTrue(hasWallet))
        {
            if (Helpers.isTrue(Helpers.isEqual(this.privateKey, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " requires a walletAddress or privateKey to watch private channels")) ;
            }
            address = this.ethGetAddressFromPrivateKey(this.privateKey);
        }
        return ((String)address).toLowerCase();
    }

    public Object handleErrors(Object code, Object reason, Object url, Object method, Object headers, Object body, Object response, Object requestHeaders, Object requestBody)
    {
        // Myriad error responses are { "error": "<message>", "details": [...] } with a 4xx status
        if (Helpers.isTrue(Helpers.isEqual(response, null)))
        {
            return null;
        }
        Object error = this.safeString(response, "error");
        if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(error, null))) || Helpers.isTrue((Helpers.isEqual(error, "")))))
        {
            return null;
        }
        Object feedback = Helpers.add(Helpers.add(this.id, " "), body);
        this.throwExactlyMatchedException(Helpers.GetValue(this.exceptions, "exact"), error, feedback);
        this.throwBroadlyMatchedException(Helpers.GetValue(this.exceptions, "broad"), error, feedback);
        throw new ExchangeError((String)feedback) ;
    }

    /**
     * @ignore
     * @method
     * @name myriad#sign
     * @description builds the request url and attaches the x-api-key header for private endpoints
     * @param {string} path the endpoint path
     * @param {string|string[]} api the api group and access level
     * @param {string} method the http method
     * @param {object} params the request parameters
     * @param {object} [headers] request headers
     * @param {string} [body] the request body
     * @returns {object} a dict with url, method, body and headers
     */
    public Object sign(Object path, Object... optionalArgs)
    {
        Object api = Helpers.getArg(optionalArgs, 0, "myriad");
        Object method = Helpers.getArg(optionalArgs, 1, "GET");
        Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
        Object headers = Helpers.getArg(optionalArgs, 3, null);
        Object body = Helpers.getArg(optionalArgs, 4, null);
        Object apiGroup = ((Helpers.isTrue((api instanceof String)))) ? api : Helpers.GetValue(api, 0);
        Object baseUrls = Helpers.GetValue(this.urls, "api");
        Object baseUrl = this.safeString(baseUrls, apiGroup, ((String)Helpers.GetValue(baseUrls, "myriad")));
        Object url = Helpers.add(Helpers.add(baseUrl, "/"), this.implodeParams(path, parameters));
        Object query = this.omit(parameters, this.extractParams(path));
        if (Helpers.isTrue(Helpers.isEqual(method, "GET")))
        {
            Object querystring = this.urlencode(query);
            if (Helpers.isTrue(querystring))
            {
                url = Helpers.add(url, Helpers.add("?", querystring));
            }
        }
        Object existingHeaders = ((Helpers.isTrue((!Helpers.isEqual(headers, null))))) ? headers : new java.util.HashMap<String, Object>() {{}};
        headers = this.extend(new java.util.HashMap<String, Object>() {{
            put( "Accept", "application/json" );
            put( "Content-Type", "application/json" );
        }}, existingHeaders);
        // non-GET requests carry the params as a JSON body (public POSTs like markets/quote
        // included — the previous logic only sent a body for authenticated requests)
        if (Helpers.isTrue(!Helpers.isEqual(method, "GET")))
        {
            Object queryKeys = Helpers.objectKeys(query);
            Object queryKeysLength = Helpers.getArrayLength(queryKeys);
            if (Helpers.isTrue(Helpers.isGreaterThan(queryKeysLength, 0)))
            {
                body = this.json(query);
            }
        }
        if (Helpers.isTrue(this.apiKey))
        {
            headers = this.extend(headers, new java.util.HashMap<String, Object>() {{
                put( "x-api-key", MyriadCore.this.apiKey );
            }});
        }
        final Object finalUrl = url;
        final Object finalMethod = method;
        final Object finalBody = body;
        final Object finalHeaders = headers;
        return new java.util.HashMap<String, Object>() {{
            put( "url", finalUrl );
            put( "method", finalMethod );
            put( "body", finalBody );
            put( "headers", finalHeaders );
        }};
    }
